313	  return async function (
314	    _ctx: AgentContext,
315	    payload: StreamChunk,
316	  ): Promise<undefined> {
317	    // Defensive: a malformed event from the bus shouldn't tear down the
318	    // host. The schema validation already happened in the IPC handler
319	    // (Task 5); this is belt-and-braces.
320	    if (typeof payload?.reqId !== 'string' || typeof payload?.kind !== 'string') {
321	      return undefined;
322	    }
323	    if (payload.kind === 'text' || payload.kind === 'thinking') {
324	      if (typeof (payload as { text?: unknown }).text !== 'string') {
325	        return undefined;
326	      }
327	      buffer.append(payload as StreamChunk);
328	      return undefined;
329	    }
330	    if (payload.kind === 'tool-use') {
331	      const p = payload as {
332	        toolCallId?: unknown;
333	        toolName?: unknown;
334	        input?: unknown;
335	      };
336	      if (
337	        typeof p.toolCallId !== 'string' ||
338	        typeof p.toolName !== 'string' ||
339	        typeof p.input !== 'object' ||
340	        p.input === null ||
341	        Array.isArray(p.input)
342	      ) {
343	        return undefined;
344	      }
345	      buffer.append(payload as StreamChunk);
346	      return undefined;
347	    }
348	    if (payload.kind === 'tool-result') {
349	      const p = payload as {
350	        toolCallId?: unknown;
351	        output?: unknown;
352	        isError?: unknown;
353	      };
354	      if (
355	        typeof p.toolCallId !== 'string' ||
356	        typeof p.output !== 'string' ||
357	        (p.isError !== undefined && typeof p.isError !== 'boolean')
358	      ) {
359	        return undefined;
360	      }
361	      buffer.append(payload as StreamChunk);
362	      return undefined;
363	    }
364	    return undefined;
365	  };
366	}
