369	 * Sister to `createBufferFillSubscriber`, but for `chat:phase`. Captures
370	 * the latest phase per reqId so an SSE handler attaching after the phase
371	 * fired still sees it on replay.
372	 */
373	export function createPhaseFillSubscriber(buffer: ChunkBuffer) {
374	  return async function (
375	    _ctx: AgentContext,
376	    payload: PhaseEvent,
377	  ): Promise<undefined> {
378	    if (
379	      typeof payload?.reqId !== 'string' ||
380	      payload.reqId.length === 0 ||
381	      payload?.phase !== 'sandbox-starting'
382	    ) {
383	      return undefined;
384	    }
385	    buffer.appendPhase(payload.reqId, payload.phase);
386	    return undefined;
387	  };
388	}
389	
390	/**
391	 * Turn-end subscriber the plugin attaches at boot. Pre-evicts the buffer
392	 * for reqIds that ended successfully so the per-connection turn-end
393	 * subscriber is the only path that needs to fire the done frame. Lives
394	 * here for the same one-file reason as the chunk filler.
395	 *
396	 * NOTE: this subscriber MUST NOT close any per-connection streams — it
397	 * runs on the host bus and doesn't know about the SSE handlers. Per-
398	 * connection turn-end handling is inside `createSseHandler` and matches
399	 * `ctx.conversationId`. We keep this subscriber separate because a
400	 * conversation may end without any SSE listener attached, and the
401	 * buffer should still be cleaned up.
402	 */
403	export function createTurnEndEvictor(buffer: ChunkBuffer) {
404	  return async function (
405	    _ctx: AgentContext,
406	    payload: { reqId?: string },
407	  ): Promise<undefined> {
408	    if (typeof payload?.reqId === 'string' && payload.reqId.length > 0) {
409	      buffer.evictReqId(payload.reqId);
410	    }
411	    return undefined;
412	  };
413	}
