**SSE parser (in processResponseStream)** — Lines 416-543:

The SSE parser is embedded in the TransformStream, not a separate exported function. Lines 420-543:

```typescript
protected processResponseStream(
  stream: ReadableStream<Uint8Array>,
): ReadableStream<UIMessageChunk> {
  let textCounter = 0;
  let thinkingCounter = 0;
  let openText: string | null = null;
  let openThinking: string | null = null;
  let finished = false;
  let carry = '';
  let contentSeen = false;

  // ... helper functions ...

  return stream
    .pipeThrough(new TextDecoderStream() as ReadableWritablePair<string, Uint8Array>)
    .pipeThrough(
      new TransformStream<string, UIMessageChunk>({
        transform(rawChunk, controller) {
          if (finished) return;
          const data = carry + rawChunk;
          const lines = data.split('\n');
          // Last element may be incomplete — carry it to the next chunk.
          carry = lines.pop() ?? '';

          for (const line of lines) {
            const trimmed = line.trim();
            if (!trimmed || trimmed.startsWith(':')) continue;
            if (!trimmed.startsWith('data: ')) continue;

            let frame: SseFrame;
            try {
              frame = JSON.parse(trimmed.slice(6)) as SseFrame;
            } catch {
              // Malformed JSON — skip.
              continue;
            }

            if ('done' in frame && frame.done === true) {
              closeOpen(controller);
              controller.enqueue({ type: 'finish', finishReason: 'stop' });
              finished = true;
              return;
            }
            // ... handle phase, text, thinking, tool-use, tool-result frames ...
          }
        },
        flush(controller) {
          if (finished) return;
          closeOpen(controller);
          controller.enqueue({ type: 'finish', finishReason: 'stop' });
          finished = true;
        },
      }),
    );
}
```

The key line is: `frame = JSON.parse(trimmed.slice(6)) as SseFrame;` — this parses `data: {...}` by slicing off the first 6 characters.

